import numpy as np

class IVFIndex:
    def __init__(self, nlist: int, nprobe: int):
        self.nlist = nlist
        self.nprobe = nprobe
        self.centroids = None  # (nlist, d)
        self.inverted_lists = {i: [] for i in range(nlist)}  # cluster_id -> [(vec, id)]

    def _kmeans(self, data: np.ndarray, K: int) -> np.ndarray:
        rng = np.random.RandomState(0)
        n = len(data)
        indices = rng.choice(n, K, replace=False)
        centroids = data[indices].copy()
        for _ in range(10):
            dists = np.linalg.norm(data[:, None, :] - centroids[None, :, :], axis=2)
            assignments = np.argmin(dists, axis=1)
            new_centroids = np.zeros_like(centroids)
            for k in range(K):
                mask = assignments == k
                if mask.sum() > 0:
                    new_centroids[k] = data[mask].mean(axis=0)
                else:
                    new_centroids[k] = centroids[k]
            centroids = new_centroids
        return centroids

    def train(self, vectors: np.ndarray) -> None:
        self.centroids = self._kmeans(vectors, self.nlist)

    def _assign_to_cluster(self, vectors: np.ndarray) -> np.ndarray:
        dists = np.linalg.norm(vectors[:, None, :] - self.centroids[None, :, :], axis=2)
        return np.argmin(dists, axis=1)

    def add(self, vectors: np.ndarray, ids: list) -> None:
        assignments = self._assign_to_cluster(vectors)
        norms = np.linalg.norm(vectors, axis=1, keepdims=True)
        normalized = vectors / (norms + 1e-10)
        for i, (cluster_id, doc_id) in enumerate(zip(assignments, ids)):
            self.inverted_lists[int(cluster_id)].append((normalized[i], doc_id))

    def search(self, query: np.ndarray, top_k: int) -> list:
        query_norm = query / (np.linalg.norm(query) + 1e-10)
        # Find nprobe nearest centroids
        centroid_dists = np.linalg.norm(self.centroids - query_norm[None, :], axis=1)
        probe_clusters = np.argsort(centroid_dists)[:self.nprobe]
        # Gather candidates from selected clusters
        candidates = []
        for cluster_id in probe_clusters:
            for vec, doc_id in self.inverted_lists[int(cluster_id)]:
                sim = float(vec @ query_norm)
                candidates.append((sim, doc_id))
        # Sort by similarity descending
        candidates.sort(key=lambda x: -x[0])
        return [doc_id for _, doc_id in candidates[:top_k]]
